import os
import glob
import json
import uuid
from dataclasses import dataclass, field
from typing import List, Dict, Any, Optional, Tuple

import chromadb
from chromadb.config import Settings
from sentence_transformers import SentenceTransformer
from pypdf import PdfReader


@dataclass
class DocumentChunk:
    id: str
    text: str
    source: str
    metadata: Dict[str, Any] = field(default_factory=dict)


class DocumentLoader:
    def __init__(self, docs_path: str):
        self.docs_path = docs_path

    def load(self) -> List[Tuple[str, str, Dict[str, Any]]]:
        documents = []
        patterns = ["**/*.txt", "**/*.md", "**/*.pdf", "**/*.json"]
        for pattern in patterns:
            for path in glob.glob(os.path.join(self.docs_path, pattern), recursive=True):
                ext = os.path.splitext(path)[1].lower()
                try:
                    if ext in [".txt", ".md"]:
                        with open(path, "r", encoding="utf-8") as f:
                            text = f.read()
                        documents.append((path, text, {"file_type": ext}))
                    elif ext == ".pdf":
                        text = self._load_pdf(path)
                        documents.append((path, text, {"file_type": ext}))
                    elif ext == ".json":
                        text = self._load_json(path)
                        documents.append((path, text, {"file_type": ext}))
                except Exception as e:
                    print(f"Failed to load {path}: {e}")
        return documents

    def _load_pdf(self, path: str) -> str:
        reader = PdfReader(path)
        pages = []
        for page in reader.pages:
            pages.append(page.extract_text() or "")
        return "\n".join(pages)

    def _load_json(self, path: str) -> str:
        with open(path, "r", encoding="utf-8") as f:
            data = json.load(f)
        return json.dumps(data, ensure_ascii=False, indent=2)


class TextChunker:
    def __init__(self, chunk_size: int = 1000, chunk_overlap: int = 150):
        self.chunk_size = chunk_size
        self.chunk_overlap = chunk_overlap

    def chunk_documents(self, documents: List[Tuple[str, str, Dict[str, Any]]]) -> List[DocumentChunk]:
        chunks = []
        for source, text, metadata in documents:
            source_chunks = self._chunk_text(text)
            for idx, chunk_text in enumerate(source_chunks):
                chunk_id = str(uuid.uuid4())
                chunk_metadata = {
                    **metadata,
                    "source": source,
                    "chunk_index": idx,
                }
                chunks.append(
                    DocumentChunk(
                        id=chunk_id,
                        text=chunk_text,
                        source=source,
                        metadata=chunk_metadata,
                    )
                )
        return chunks

    def _chunk_text(self, text: str) -> List[str]:
        text = text.strip()
        if not text:
            return []

        chunks = []
        start = 0
        text_len = len(text)

        while start < text_len:
            end = min(start + self.chunk_size, text_len)
            chunk = text[start:end]

            if end < text_len:
                last_break = max(
                    chunk.rfind("\n\n"),
                    chunk.rfind("\n"),
                    chunk.rfind(". "),
                    chunk.rfind(" "),
                )
                if last_break > self.chunk_size // 2:
                    end = start + last_break + 1
                    chunk = text[start:end]

            chunks.append(chunk.strip())
            next_start = end - self.chunk_overlap
            if next_start <= start:
                next_start = end
            start = next_start

        return [c for c in chunks if c]


class EmbeddingModel:
    def __init__(self, model_name: str = "sentence-transformers/all-MiniLM-L6-v2"):
        self.model = SentenceTransformer(model_name)

    def embed_texts(self, texts: List[str]) -> List[List[float]]:
        return self.model.encode(texts, convert_to_numpy=True).tolist()

    def embed_query(self, text: str) -> List[float]:
        return self.model.encode([text], convert_to_numpy=True)[0].tolist()


class VectorStore:
    def __init__(
        self,
        persist_directory: str = "./chroma_db",
        collection_name: str = "company_knowledge_base",
    ):
        self.client = chromadb.PersistentClient(path=persist_directory, settings=Settings(anonymized_telemetry=False))
        self.collection = self.client.get_or_create_collection(name=collection_name)

    def add_chunks(self, chunks: List[DocumentChunk], embeddings: List[List[float]]) -> None:
        if not chunks:
            return

        ids = [chunk.id for chunk in chunks]
        documents = [chunk.text for chunk in chunks]
        metadatas = [chunk.metadata for chunk in chunks]

        self.collection.add(
            ids=ids,
            documents=documents,
            metadatas=metadatas,
            embeddings=embeddings,
        )

    def query(self, query_embedding: List[float], top_k: int = 5) -> List[Dict[str, Any]]:
        result = self.collection.query(
            query_embeddings=[query_embedding],
            n_results=top_k,
            include=["documents", "metadatas", "distances"],
        )

        retrieved = []
        docs = result.get("documents", [[]])[0]
        metas = result.get("metadatas", [[]])[0]
        dists = result.get("distances", [[]])[0]

        for doc, meta, dist in zip(docs, metas, dists):
            retrieved.append(
                {
                    "text": doc,
                    "metadata": meta,
                    "distance": dist,
                }
            )
        return retrieved

    def count(self) -> int:
        return self.collection.count()


class PromptBuilder:
    @staticmethod
    def build(query: str, retrieved_docs: List[Dict[str, Any]]) -> str:
        context_sections = []
        for i, doc in enumerate(retrieved_docs, start=1):
            source = doc.get("metadata", {}).get("source", "unknown")
            chunk_index = doc.get("metadata", {}).get("chunk_index", "unknown")
            context_sections.append(
                f"[Document {i}]\n"
                f"Source: {source}\n"
                f"Chunk: {chunk_index}\n"
                f"Content:\n{doc['text']}"
            )

        all_context = "\n\n".join(context_sections)

        return (
            "You are an internal company knowledge base assistant.\n"
            "Use the provided context to answer the user's question.\n"
            "If the answer is not in the context, say you do not have enough information.\n"
            "Cite source document paths when possible.\n\n"
            f"Retrieved Context:\n{all_context}\n\n"
            f"User Question:\n{query}\n\n"
            "Answer:"
        )


class LLMClient:
    def __init__(self, api_key: Optional[str] = None, model: str = "gpt-4o-mini"):
        self.api_key = api_key or os.getenv("OPENAI_API_KEY")
        self.model = model

    def generate(self, prompt: str) -> str:
        try:
            from openai import OpenAI
        except ImportError:
            raise ImportError("Please install openai: pip install openai")

        if not self.api_key:
            raise ValueError("OPENAI_API_KEY not set")

        client = OpenAI(api_key=self.api_key)
        response = client.chat.completions.create(
            model=self.model,
            messages=[
                {"role": "system", "content": "You answer questions using retrieved internal company documents."},
                {"role": "user", "content": prompt},
            ],
            temperature=0.2,
        )
        return response.choices[0].message.content or ""


class RAGSystem:
    def __init__(
        self,
        docs_path: str,
        persist_directory: str = "./chroma_db",
        collection_name: str = "company_knowledge_base",
        embedding_model_name: str = "sentence-transformers/all-MiniLM-L6-v2",
        llm_model: str = "gpt-4o-mini",
    ):
        self.loader = DocumentLoader(docs_path)
        self.chunker = TextChunker()
        self.embedder = EmbeddingModel(embedding_model_name)
        self.vector_store = VectorStore(persist_directory, collection_name)
        self.llm = LLMClient(model=llm_model)

    def index_documents(self, reset_collection: bool = False) -> None:
        if reset_collection:
            name = self.vector_store.collection.name
            self.vector_store.client.delete_collection(name)
            self.vector_store.collection = self.vector_store.client.get_or_create_collection(name=name)

        raw_documents = self.loader.load()
        chunks = self.chunker.chunk_documents(raw_documents)

        if not chunks:
            print("No documents found to index.")
            return

        batch_size = 64
        for i in range(0, len(chunks), batch_size):
            batch = chunks[i:i + batch_size]
            texts = [c.text for c in batch]
            embeddings = self.embedder.embed_texts(texts)
            self.vector_store.add_chunks(batch, embeddings)
            print(f"Indexed {min(i + batch_size, len(chunks))}/{len(chunks)} chunks")

        print(f"Indexing complete. Total vectors: {self.vector_store.count()}")

    def retrieve(self, query: str, top_k: int = 5) -> List[Dict[str, Any]]:
        query_embedding = self.embedder.embed_query(query)
        return self.vector_store.query(query_embedding, top_k=top_k)

    def answer(self, query: str, top_k: int = 5) -> Dict[str, Any]:
        retrieved_docs = self.retrieve(query, top_k=top_k)
        prompt = PromptBuilder.build(query, retrieved_docs)
        answer = self.llm.generate(prompt)
        return {
            "query": query,
            "answer": answer,
            "retrieved_documents": retrieved_docs,
            "prompt": prompt,
        }


def main():
    import argparse

    parser = argparse.ArgumentParser(description="Internal Knowledge Base RAG System")
    parser.add_argument("--docs-path", type=str, default="./documents", help="Path to company documents")
    parser.add_argument("--persist-directory", type=str, default="./chroma_db", help="Chroma persistence directory")
    parser.add_argument("--collection-name", type=str, default="company_knowledge_base", help="Vector DB collection name")
    parser.add_argument("--index", action="store_true", help="Index documents into vector database")
    parser.add_argument("--reset", action="store_true", help="Reset collection before indexing")
    parser.add_argument("--query", type=str, help="User query")
    parser.add_argument("--top-k", type=int, default=5, help="Number of documents to retrieve")
    parser.add_argument("--show-prompt", action="store_true", help="Print full LLM prompt")
    args = parser.parse_args()

    rag = RAGSystem(
        docs_path=args.docs_path,
        persist_directory=args.persist_directory,
        collection_name=args.collection_name,
    )

    if args.index:
        rag.index_documents(reset_collection=args.reset)

    if args.query:
        result = rag.answer(args.query, top_k=args.top_k)
        print("\n=== ANSWER ===")
        print(result["answer"])

        print("\n=== RETRIEVED DOCUMENTS ===")
        for i, doc in enumerate(result["retrieved_documents"], start=1):
            print(f"\n[{i}] Source: {doc['metadata'].get('source')}")
            print(f"Chunk: {doc['metadata'].get('chunk_index')}")
            print(f"Distance: {doc['distance']}")
            print(doc["text"][:1000])

        if args.show_prompt:
            print("\n=== FULL PROMPT ===")
            print(result["prompt"])


if __name__ == "__main__":
    main()